INSERT INTO about_sections VALUES(1,'Our founding','We started with a simple idea: modern websites should be easy to build, fast to launch, and pleasant to maintain. Today we help teams ship clean, responsive experiences with a solid technical foundation.','https://source.unsplash.com/600x400/?coding,team',1,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO about_sections VALUES(2,'Growth & beyond','As we grew, we focused on great UX, maintainable code, and clear content structure. The result is a site that can scale — from a landing page to a full content-driven platform.','https://source.unsplash.com/600x400/?coding,growth',2,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO faq_items VALUES(1,1,'How do I change my password?','Go to your profile page and use the “Update Password” form.',1,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO faq_items VALUES(2,1,'Can I cancel anytime?','Yes. You can change or cancel your plan at any time from your account settings.',2,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO faq_items VALUES(3,1,'Do you offer refunds?','If you were charged by mistake, contact support and we will help you right away.',3,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO faq_items VALUES(4,2,'The site looks broken on my phone. What do I do?','Try refreshing the page, then clear browser cache. If the issue persists, contact support.',1,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO faq_items VALUES(5,2,'I found a bug. Where can I report it?','Use the contact form to send us details and screenshots — we will respond quickly.',2,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO faq_items VALUES(6,2,'Why is my page loading slowly?','Performance depends on network and device. We recommend checking your connection and trying again.',3,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
