INSERT INTO portfolio_projects VALUES(1,'E-commerce Redesign','ecommerce-redesign','A modern storefront refresh with improved conversion and mobile UX.','We redesigned a legacy e-commerce site into a clean, responsive experience. The new layout improves browsing, checkout flow, and content clarity across devices.','https://source.unsplash.com/1300x700/?code,ecommerce','https://example.com','Acme Retail','2025-11-05 00:00:00','2026-01-05 00:00:00',1,1,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO portfolio_projects VALUES(2,'SaaS Landing Page','saas-landing-page','High-performance marketing page optimized for speed and clarity.','A focused landing page with clear messaging, pricing, and lead capture. Built with reusable sections and clean structure for future expansion.','https://source.unsplash.com/1300x700/?code,saas','https://example.com','Nova Studio','2025-12-05 00:00:00','2025-12-19 00:00:00',0,2,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO portfolio_projects VALUES(3,'Portfolio Website','portfolio-website','A clean portfolio layout for showcasing projects and blog content.','A structured portfolio site with dynamic projects and a blog section. Easy to maintain, fast to load, and responsive across devices.','https://source.unsplash.com/1300x700/?code,portfolio','https://example.com','Freelance','2026-01-05 00:00:00','2026-02-05 00:00:00',0,3,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
INSERT INTO portfolio_projects VALUES(4,'Company Blog & CMS','company-blog-cms','A content-driven blog with categories, tags, and admin management.','A blog foundation with admin CRUD for posts, categories, and tags, plus public listing and post pages.','https://source.unsplash.com/1300x700/?code,blog','https://example.com','Internal','2026-02-05 00:00:00','2026-02-19 00:00:00',0,4,1,'2026-03-05 10:47:40','2026-03-05 10:47:40');
