PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "role" varchar not null default 'user');
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "categories" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "post_tags" ("id" integer primary key autoincrement not null, "post_id" integer not null, "tag_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("post_id") references "posts"("id") on delete cascade, foreign key("tag_id") references "tags"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "posts" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "content" text not null, "user_id" integer not null, "category_id" integer not null, "published_at" datetime, "created_at" datetime, "updated_at" datetime, "image_url" varchar, foreign key("user_id") references "users"("id") on delete cascade, foreign key("category_id") references "categories"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "tags" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "home_features" ("id" integer primary key autoincrement not null, "title" varchar not null, "description" text, "icon" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "site_settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "about_sections" ("id" integer primary key autoincrement not null, "title" varchar not null, "body" text, "image_url" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "contact_messages" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "phone" varchar, "message" text not null, "status" varchar not null default 'new', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "faq_items" ("id" integer primary key autoincrement not null, "faq_section_id" integer not null, "question" varchar not null, "answer" text not null, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("faq_section_id") references "faq_sections"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "faq_sections" ("id" integer primary key autoincrement not null, "title" varchar not null, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "portfolio_project_images" ("id" integer primary key autoincrement not null, "portfolio_project_id" integer not null, "image_url" varchar not null, "caption" varchar, "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("portfolio_project_id") references "portfolio_projects"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "portfolio_projects" ("id" integer primary key autoincrement not null, "title" varchar not null, "slug" varchar not null, "excerpt" text, "description" text, "hero_image_url" varchar, "project_url" varchar, "client" varchar, "started_at" date, "finished_at" date, "is_featured" tinyint(1) not null default '0', "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "pricing_plan_features" ("id" integer primary key autoincrement not null, "pricing_plan_id" integer not null, "feature" varchar not null, "is_included" tinyint(1) not null default '1', "sort_order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("pricing_plan_id") references "pricing_plans"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "pricing_plans" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "badge" varchar, "price_cents" integer not null default '0', "currency" varchar not null default 'USD', "billing_period" varchar not null default 'mo', "is_featured" tinyint(1) not null default '0', "cta_text" varchar not null default 'Choose plan', "cta_url" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "team_members" ("id" integer primary key autoincrement not null, "name" varchar not null, "role" varchar, "avatar_url" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "testimonials" ("id" integer primary key autoincrement not null, "name" varchar not null, "role" varchar, "company" varchar, "quote" text not null, "avatar_url" varchar, "sort_order" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE INDEX "users_role_index" on "users" ("role");
CREATE UNIQUE INDEX "categories_name_unique" on "categories" ("name");
CREATE UNIQUE INDEX "categories_slug_unique" on "categories" ("slug");
CREATE UNIQUE INDEX "post_tags_post_id_tag_id_unique" on "post_tags" ("post_id", "tag_id");
CREATE UNIQUE INDEX "posts_slug_unique" on "posts" ("slug");
CREATE UNIQUE INDEX "tags_name_unique" on "tags" ("name");
CREATE UNIQUE INDEX "tags_slug_unique" on "tags" ("slug");
CREATE INDEX "home_features_sort_order_index" on "home_features" ("sort_order");
CREATE INDEX "home_features_is_active_index" on "home_features" ("is_active");
CREATE UNIQUE INDEX "site_settings_key_unique" on "site_settings" ("key");
CREATE INDEX "about_sections_sort_order_index" on "about_sections" ("sort_order");
CREATE INDEX "about_sections_is_active_index" on "about_sections" ("is_active");
CREATE INDEX "contact_messages_status_index" on "contact_messages" ("status");
CREATE INDEX "faq_items_sort_order_index" on "faq_items" ("sort_order");
CREATE INDEX "faq_items_is_active_index" on "faq_items" ("is_active");
CREATE INDEX "faq_sections_sort_order_index" on "faq_sections" ("sort_order");
CREATE INDEX "faq_sections_is_active_index" on "faq_sections" ("is_active");
CREATE INDEX "portfolio_project_images_sort_order_index" on "portfolio_project_images" ("sort_order");
CREATE UNIQUE INDEX "portfolio_projects_slug_unique" on "portfolio_projects" ("slug");
CREATE INDEX "portfolio_projects_is_featured_index" on "portfolio_projects" ("is_featured");
CREATE INDEX "portfolio_projects_sort_order_index" on "portfolio_projects" ("sort_order");
CREATE INDEX "portfolio_projects_is_active_index" on "portfolio_projects" ("is_active");
CREATE INDEX "pricing_plan_features_sort_order_index" on "pricing_plan_features" ("sort_order");
CREATE UNIQUE INDEX "pricing_plans_slug_unique" on "pricing_plans" ("slug");
CREATE INDEX "pricing_plans_is_featured_index" on "pricing_plans" ("is_featured");
CREATE INDEX "pricing_plans_sort_order_index" on "pricing_plans" ("sort_order");
CREATE INDEX "pricing_plans_is_active_index" on "pricing_plans" ("is_active");
CREATE INDEX "team_members_sort_order_index" on "team_members" ("sort_order");
CREATE INDEX "team_members_is_active_index" on "team_members" ("is_active");
CREATE INDEX "testimonials_sort_order_index" on "testimonials" ("sort_order");
CREATE INDEX "testimonials_is_active_index" on "testimonials" ("is_active");
COMMIT;
